var n = 0
for e in ReplayManager._recording_events:
	var ad = e.get("action_data", {})
	if ad.has("_replay_diffs") or ad.has("_ai_decision_records") or ad.has("_ai_thinking_steps") or ad.has("_ai_thinking_context"):
		n += 1
return n

var n = 0
for ph in GameState.state["history"]:
	for a in ph.get("actions", []):
		if a.has("_replay_diffs") or a.has("_ai_decision_records") or a.has("_ai_thinking_steps"):
			n += 1
return n

var n = 0
for s in ReplayManager._recording_snapshots:
	var st = s.get("state", {})
	if not st.get("history", []).is_empty() or not st.get("phase_log", []).is_empty():
		n += 1
return n

var n = 0
for a in ActionLogger.session_actions:
	if a.has("_replay_diffs") or a.has("_ai_decision_records"):
		n += 1
return n
